module RefModule (counter_out, clk, reset, en, load, load_value);
   input clk, reset, en, load;
   input [7:0] load_value;
   output [7:0] counter_out;

   reg [7:0] counter_out;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
      if (reset)
         counter_out <= 8'b0;
      else if (load)
         counter_out <= load_value;
      else if (en)
         counter_out <= counter_out + 1;
   end

endmodule
